const ALPHABET = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
const BASE = 62n;

export function encodeBase62(id: bigint): string {
  if (id === 0n) return ALPHABET[0];
  let out = '';
  while (id > 0n) {
    out = ALPHABET[Number(id % BASE)] + out;
    id = id / BASE;
  }
  return out;
}

export function decodeBase62(code: string): bigint {
  let id = 0n;
  for (const ch of code) {
    id = id * BASE + BigInt(ALPHABET.indexOf(ch));
  }
  return id;
}
// encodeBase62(125n) -> 'cb' ; collision-free because IDs are unique

async function deliver(msg: ChatMessage, recipients: string[]) {
  // Persist once for history + ordering (monotonic per-conversation seq)
  const seq = await store.appendMessage(msg.conversationId, msg);
  msg.seq = seq;

  for (const userId of recipients) {
    const gatewayId = await sessionRegistry.get(userId); // Redis
    if (gatewayId) {
      // online: push via the gateway that owns the socket
      await broker.publish(`gw.${gatewayId}`, { userId, msg });
    } else {
      // offline: queue a push notification, deliver on reconnect
      await pushQueue.enqueue({ userId, msg });
    }
  }
}

// Redis-backed live courier index (GEO commands use a sorted set internally)
async function updateCourier(id: string, lng: number, lat: number) {
  await redis.geoadd('couriers:live', lng, lat, id);
  await redis.expire(`courier:${id}:ttl`, 30); // stale couriers drop out
}

async function nearbyCouriers(lng: number, lat: number, radiusKm = 3) {
  // returns ids sorted by distance, with distance attached
  return redis.geosearch(
    'couriers:live',
    'FROMLONLAT', lng, lat,
    'BYRADIUS', radiusKm, 'km',
    'ASC', 'WITHDIST', 'COUNT', 20
  );
}

async function processNotification(job: NotificationJob) {
  if (await dedup.seen(job.idempotencyKey)) return;        // at-least-once dedup
  if (!(await userBucket.allow(job.userId))) return defer(job);
  if (!(await providerBucket.allow(job.channel))) return requeueLater(job);

  try {
    await providers[job.channel].send(renderTemplate(job));
    await dedup.mark(job.idempotencyKey);
  } catch (err) {
    if (job.attempts >= MAX_RETRIES || isPermanent(err)) {
      await dlq.publish(job, err);                          // poison -> DLQ
    } else {
      const delay = backoffWithJitter(job.attempts);
      await queue.requeue(job, delay);
    }
  }
}

// The fix: provider token bucket + jittered backoff + circuit breaker
const providerBucket = new TokenBucket({ ratePerSec: 5000, burst: 5000 });

async function send(job: Job) {
  await providerBucket.take();              // never exceed provider TPS
  if (breaker.isOpen()) return requeueLater(job, breaker.cooldown());
  try {
    await provider.push(job);
    breaker.recordSuccess();
  } catch (e) {
    breaker.recordFailure();
    const base = Math.min(2 ** job.attempts * 100, 30_000);
    const delay = base / 2 + Math.random() * (base / 2); // full jitter
    await queue.requeue(job, delay);
  }
}

