const ALPHABET =
  'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
const BASE = 62n;
const INDEX: Record<string, number> = {};
for (let i = 0; i < ALPHABET.length; i++) INDEX[ALPHABET[i]] = i;

export function encode(id: bigint): string {
  if (id < 0n) throw new Error('id must be non-negative');
  if (id === 0n) return ALPHABET[0];
  let out = '';
  while (id > 0n) {
    out = ALPHABET[Number(id % BASE)] + out;
    id = id / BASE;
  }
  return out;
}

export function decode(code: string): bigint {
  let id = 0n;
  for (const ch of code) {
    const v = INDEX[ch];
    if (v === undefined) throw new Error(`invalid char: ${ch}`);
    id = id * BASE + BigInt(v);
  }
  return id;
}

// Bijective scramble: multiply by a constant coprime to the modulus.
// gcd(PRIME, MOD) = 1 guarantees a 1:1 mapping, preserving uniqueness.
const MOD = 62n ** 7n;          // 7-char keyspace
const PRIME = 2654435761n;       // Knuth multiplicative-hash constant
export function scramble(id: bigint): bigint {
  return (id * PRIME) % MOD;     // still unique, but non-sequential
}

// Round-trip check
const id = 1_000_000n;
console.assert(decode(encode(id)) === id, 'codec must round-trip');
const code = encode(scramble(id));
console.log(code); // a non-sequential, collision-free short code

// Lua runs atomically inside Redis: no race between read and write.
const BUCKET_LUA = `
local key      = KEYS[1]
local rate     = tonumber(ARGV[1])   -- tokens per second
local burst    = tonumber(ARGV[2])   -- max tokens
local now      = tonumber(ARGV[3])   -- ms epoch
local state    = redis.call('HMGET', key, 'tokens', 'ts')
local tokens   = tonumber(state[1])
local ts       = tonumber(state[2])
if tokens == nil then tokens = burst; ts = now end

local elapsed  = math.max(0, now - ts) / 1000.0
tokens = math.min(burst, tokens + elapsed * rate)

local allowed, wait_ms = 0, 0
if tokens >= 1 then
  tokens = tokens - 1
  allowed = 1
else
  wait_ms = math.ceil((1 - tokens) / rate * 1000)
end

redis.call('HMSET', key, 'tokens', tokens, 'ts', now)
redis.call('PEXPIRE', key, math.ceil(burst / rate * 1000) + 1000)
return { allowed, wait_ms }
`;

export class TokenBucket {
  private sha?: string;
  constructor(
    private redis: any,
    private key: string,
    private ratePerSec: number,
    private burst: number,
  ) {}

  async tryTake(): Promise<{ allowed: boolean; waitMs: number }> {
    if (!this.sha) this.sha = await this.redis.scriptLoad(BUCKET_LUA);
    const [allowed, waitMs] = await this.redis.evalsha(
      this.sha, 1, this.key,
      this.ratePerSec, this.burst, Date.now(),
    );
    return { allowed: allowed === 1, waitMs };
  }

  // Block until a token is available, respecting the server-computed wait.
  async take(): Promise<void> {
    for (;;) {
      const { allowed, waitMs } = await this.tryTake();
      if (allowed) return;
      await new Promise((r) => setTimeout(r, waitMs));
    }
  }
}
